python3 -c "import re, glob; files = ['scripts/db-ticket.sh', 'scripts/db-sprint.sh']; files += [p for p in glob.glob('scripts/*.sh') if 'db-' in p or 'async' in p or 'auto-heal' in p or 'backup' in p or 'check-model' in p or 'flash-dispatcher' in p or 'master-synthesize' in p or 'model-policy' in p or 'nightly-restart' in p or 'sprint-fk' in p']; 
for path in files:
    try:
        with open(path, 'r') as f:
            text = f.read()
    except Exception:
        continue
    text2 = re.sub(
        r'JQ="\$\(command -v jq 2>/dev/null \|\| brew --prefix 2>/dev/null\)/bin/jq"',
        'JQ=\"__JQ_DEF_PLACEHOLDER__\"',
        text
    )
    text2 = re.sub(
        r'\$\(command -v jq 2>/dev/null \|\| brew --prefix 2>/dev/null\)/bin/jq',
        '$JQ',
        text2
    )
    text2 = text2.replace('JQ=\"__JQ_DEF_PLACEHOLDER__\"', 'JQ=\"(command -v jq 2>/dev/null || brew --prefix 2>/dev/null)/bin/jq"')
    pattern2 = re.compile(
        r'^(\s*)([a-zA-Z_][a-zA-Z0-9_]*)=\$JQ\s+(-n\s+.+?\}')(?:\s*2>/dev/null)?(\s*\|\|\s+.+)$',
        re.MULTILINE
    )
    def repl2(m):
        indent = m.group(1)
        var = m.group(2)
        jq_part = m.group(3)
        fallback = m.group(4)
        if fallback.rstrip().endswith(')'):
            fallback = fallback.rstrip()[:-1]
        return f'{indent}{var}=$($JQ {jq_part} 2>/dev/null{fallback})'
    text2 = pattern2.sub(repl2, text2)
    if text2 != text:
        with open(path, 'w') as f:
            f.write(text2)
        print(f'Fixed {path}')
    else:
        print(f'No changes {path}')"

